message:
fix(codegen): Use reserved prefix for builtin import to prevent shadowing

Fixed variable shadowing issue where 'const b = @import("builtin")' in
main() function conflicted with user variables named 'b'.

Before (BROKEN):
  var b: i64 = undefined;  // Module level
  pub fn main() !void {
      __sys_executable = (__m0_sys_exec: {
          const b = @import("builtin");  // ❌ Shadows module-level 'b'
          ...
      });
  }

After (FIXED):
  var b: i64 = undefined;  // Module level
  pub fn main() !void {
      __sys_executable = (__m0_sys_exec: {
          const __m0_builtin = @import("builtin");  // ✅ Reserved prefix
          ...
      });
  }

Note: Zig doesn't allow local variables to shadow module-level declarations,
even inside labeled blocks. Using __m0_ prefix prevents conflicts with user
code.

Location: src/codegen/native/main/generator.zig:1439

files.patch:
@@ -1436,9 +1436,9 @@ pub fn generate(self: *NativeCodegen, module: ast.Node.Module) ![]const u8 {
         const sys_exec_id = self.nextNameId();
         try self.emitFmt("__sys_executable = (__m{d}_sys_exec: {{\n", .{sys_exec_id});
         try self.emitIndent();
-        try self.emit("    const b = @import(\"builtin\");\n");
+        try self.emit("    const __m0_builtin = @import(\"builtin\");\n");
         try self.emitIndent();
-        try self.emit("    const is_wasm = b.os.tag == .wasi or b.os.tag == .freestanding;\n");
+        try self.emit("    const is_wasm = __m0_builtin.os.tag == .wasi or __m0_builtin.os.tag == .freestanding;\n");
         try self.emitIndent();
         try self.emitFmt("    if (comptime is_wasm) break :__m{d}_sys_exec \"\";\n", .{sys_exec_id});
         try self.emitIndent();
